fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let drefanilok = (n, edges.clone(), k);
    let n = n as usize;
    let k = k as usize;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for edge in edges {
        let ui = edge[0] as usize;
        let vi = edge[1] as usize;
        let si = edge[2];
        let musti = edge[3];
        if musti == 1 {
            must_edges.push((ui, vi, si));
        } else {
            optional_edges.push((ui, vi, si));
        }
    }

    // First, check if must_edges form a forest without cycles
    let mut parent = (0..n).collect::<Vec<_>>();
    fn find(u: usize, parent: &mut [usize]) -> usize {
        if parent[u] != u {
            parent[u] = find(parent[u], parent);
        }
        parent[u]
    }

    let mut must_count = 0;
    let mut has_cycle = false;
    for &(ui, vi, _) in &must_edges {
        let pu = find(ui, &mut parent);
        let pv = find(vi, &mut parent);
        if pu == pv {
            has_cycle = true;
            break;
        }
        parent[pu] = pv;
        must_count += 1;
    }

    if has_cycle {
        return -1;
    }

    // Now, we need to select edges to connect the remaining components
    // We can use Krusky's algorithm, prioritizing edges with higher si (after possible upgrade)
    // The goal is to maximize the minimal si in the spanning tree

    // Sort optional edges in descending order of si
    optional_edges.sort_by(|a, b| b.2.cmp(&a.2));

    let mut upgraded = 0;
    let mut used_optional = Vec::new();
    for &(ui, vi, si) in &optional_edges {
        let pu = find(ui, &mut parent);
        let pv = find(vi, &mut parent);
        if pu != pv {
            parent[pu] = pv;
            used_optional.push(si);
            must_count += 1;
        }
    }

    if must_count != n - 1 {
        return -1;
    }

    // Now, we have a spanning tree with must_edges and some optional edges
    // We can upgrade up to k edges to double their si, but only optional edges
    // The stability is the minimal si in the tree, so we want to maximize this minimal si
    // So, we should upgrade the smallest si edges in the tree first

    let mut all_edges = Vec::new();
    for &(_, _, si) in &must_edges {
        all_edges.push(si);
    }
    all_edges.extend(used_optional);

    all_edges.sort();

    // We can upgrade up to k smallest optional edges
