        // For simplicity, assume the first 'must_edges.len()' are must edges, rest are optional
        if i >= must_edges.len() {
            all_edges[i] *= 2;
            upgraded_count += 1;
        }
    }

    *all_edges.iter().min().unwrap_or(&-1)
